package com.veetu.vadagai.property;import com.veetu.vadagai.common.ApiResponse;import com.veetu.vadagai.property.PropertyDtos.*;import jakarta.validation.Valid;import lombok.RequiredArgsConstructor;import org.springframework.data.domain.*;import org.springframework.security.access.prepost.PreAuthorize;import org.springframework.web.bind.annotation.*;import java.util.UUID;
@RestController @RequestMapping("/api/v1/properties") @RequiredArgsConstructor public class PropertyController{private final PropertyService svc;@GetMapping @PreAuthorize("hasAnyRole('OWNER','ADMIN')") ApiResponse<Page<PropertyResponse>> list(@PageableDefault(size=12) Pageable p){return ApiResponse.ok("Properties",svc.mine(p));}@PostMapping @PreAuthorize("hasRole('OWNER')") ApiResponse<PropertyResponse> create(@Valid @RequestBody PropertyRequest r){return ApiResponse.ok("Property created",svc.create(r));}@PutMapping("/{id}") @PreAuthorize("hasAnyRole('OWNER','ADMIN')") ApiResponse<PropertyResponse> update(@PathVariable UUID id,@Valid @RequestBody PropertyRequest r){return ApiResponse.ok("Property updated",svc.update(id,r));}@DeleteMapping("/{id}") @PreAuthorize("hasAnyRole('OWNER','ADMIN')") ApiResponse<Void> delete(@PathVariable UUID id){svc.delete(id);return ApiResponse.ok("Property deleted",null);}}
